import { useEffect, useMemo, useState } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { Calculator, Check, CreditCard, Eye, ExternalLink, Loader2, Pencil, Plus, Printer, RefreshCw, Search, Settings2, Trash2, Users, Wallet } from "lucide-react";
import { useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Textarea } from "@/components/ui/textarea";
import { useToast } from "@/hooks/use-toast";
import { adminFetch, apiErrorMessage, apiErrorStatus } from "./_lib";
import PayrollBonuses from "./payroll-bonuses";
import { printWhenImagesReadyScript, sheetReportCss } from "./print-helpers";

const esc = (value: unknown) => String(value ?? "").replace(/[&<>'"]/g, (char) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", "'": "&#39;", '"': "&quot;" })[char] ?? char);
function printSalarySlip(run: any) { const popup = window.open("", "_blank", "noopener,noreferrer,width=900,height=700"); if (!popup) return; const rows = (run.lines ?? []).map((line: any) => `<tr><td>${esc(line.employeeName)}</td><td>${money.format(line.baseSalary)}</td><td>${money.format(line.grossSalary)}</td><td>${money.format(line.totalDeductions ?? 0)}</td><td>${money.format(line.netSalary)}</td></tr>`).join(""); popup.document.write(`<html dir="rtl"><head><title>كشف رواتب ${esc(run.period)}</title><style>${sheetReportCss("a4")}</style></head><body><main class="sheet-report"><header><h1>كشف رواتب</h1><p>الدورة: ${esc(run.run_no)} · الفترة: ${esc(run.period)}</p></header><table><thead><tr><th>الموظف</th><th>الأساسي</th><th>الإجمالي</th><th>الاستقطاعات</th><th>الصافي</th></tr></thead><tbody>${rows}</tbody></table><p class="grand">صافي الدورة: ${money.format(run.totalNet)}</p></main>${printWhenImagesReadyScript()}</body></html>`); popup.document.close(); }
function PayrollActions({ runs, selected, toggleSelected, setDetails, setEditTarget, setDeleteTarget, recalculate, submit, approve, pay, print }: any) { return <div className="mb-3 rounded-lg border p-3"><div className="mb-2 font-semibold">إجراءات الرواتب</div>{runs.map((run: any) => { const editable = ["draft", "calculated", "under_review"].includes(run.status); const deletable = run.status === "draft"; const submittable = ["draft", "calculated", "under_review", "rejected"].includes(run.status); const approvable = run.status === "pending_manager_approval"; const payable = run.status === "approved"; return <div key={run.id} className="flex flex-wrap items-center gap-2 border-t py-2"><Checkbox checked={selected.includes(run.id)} onCheckedChange={() => toggleSelected(run.id)} /><span>{run.run_no} · {run.period}</span><span className="text-xs text-muted-foreground">{run.status} · {money.format(run.totalNet)}</span><span className="ms-auto flex flex-wrap gap-1"><Button title="عرض التفاصيل" size="sm" variant="ghost" onClick={() => setDetails(run)}><Eye className="h-4 w-4" /></Button><Button title={editable ? "تعديل" : "لا يمكن تعديل راتب محمي"} size="sm" variant="ghost" disabled={!editable || !run.lines?.[0]} onClick={() => setEditTarget({ run, line: run.lines[0] })}><Pencil className="h-4 w-4" /></Button><Button title={deletable ? "حذف مسودة" : "لا يمكن حذف دورة غير مسودة"} size="sm" variant="ghost" disabled={!deletable} onClick={() => setDeleteTarget(run)}><Trash2 className="h-4 w-4" /></Button><Button title={editable ? "إعادة حساب" : "لا يمكن إعادة حساب دورة محمية"} size="sm" variant="ghost" disabled={!editable} onClick={() => recalculate.mutate(run.id)}><RefreshCw className="h-4 w-4" /></Button><Button title="إرسال لاعتماد المدير" size="sm" variant="ghost" disabled={!submittable} onClick={() => submit.mutate(run.id)}>إرسال</Button><Button title="اعتماد وصرف الدورة" size="sm" variant="ghost" disabled={!approvable} onClick={() => approve.mutate(run.id)}><Check className="h-4 w-4" /></Button><Button title={payable ? "دفع" : "لا يمكن الدفع إلا بعد الاعتماد"} size="sm" variant="ghost" disabled={!payable} onClick={() => pay.mutate(run.id)}><CreditCard className="h-4 w-4" /></Button><Button title="طباعة كشف الراتب" size="sm" variant="ghost" onClick={() => print(run)}><Printer className="h-4 w-4" /></Button></span></div>; })}</div>; }
function EditPayrollDialog({ target, onClose, onSave, saving }: any) { const line = target?.line; const [values, setValues] = useState<any>({}); if (!target) return null; const fields = ["baseSalary", "overtimeAmount", "bonusAmount", "commissionAmount", "attendanceDeduction", "absenceDeduction", "lateDeduction", "advanceDeduction", "manualDeduction", "otherEarnings", "otherDeductions"]; const current: any = { ...line, paymentDate: target.run.paymentDate ?? "", ...values }; return <Dialog open onOpenChange={(open) => !open && onClose()}><DialogContent className="max-w-3xl" dir="rtl"><DialogHeader><DialogTitle>تعديل راتب {line.employeeName}</DialogTitle></DialogHeader><div className="grid gap-3 sm:grid-cols-3">{fields.map((key) => <Field key={key} label={key}><input type="number" min="0" value={current[key] ?? 0} onChange={(e) => setValues((v: any) => ({ ...v, [key]: Number(e.target.value) }))} /></Field>)}</div><DialogFooter><Button variant="outline" onClick={onClose}>إلغاء</Button><Button disabled={saving} onClick={() => onSave(current)}>حفظ التعديل</Button></DialogFooter></DialogContent></Dialog>; }
function DeletePayrollDialog({ run, onClose, onDelete }: any) { return <Dialog open={!!run} onOpenChange={(open) => !open && onClose()}><DialogContent dir="rtl"><DialogHeader><DialogTitle>Are you sure you want to delete this payroll record?</DialogTitle><DialogDescription>{run && <span>{run.period} · {money.format(run.totalNet)} · {run.status}</span>}</DialogDescription></DialogHeader><DialogFooter><Button variant="outline" onClick={onClose}>إلغاء</Button><Button variant="destructive" onClick={onDelete}>حذف</Button></DialogFooter></DialogContent></Dialog>; }
function DeletePayrollLineDialog({ target, onClose, onDelete, busy }: { target: { run: Run; line: Line } | null; onClose: () => void; onDelete: (reason: string) => void; busy: boolean }) { const [reason, setReason] = useState(""); useEffect(() => setReason(""), [target?.line.id]); return <Dialog open={!!target} onOpenChange={(open) => !open && onClose()}><DialogContent dir="rtl"><DialogHeader><DialogTitle>حذف سجل راتب الموظف</DialogTitle><DialogDescription>{target && <span>سيُحذف سجل {target.line.employeeName} من مسودة دورة {target.run.run_no} فقط. لا يمكن استرجاعه.</span>}</DialogDescription></DialogHeader><label className="grid gap-1 text-sm"><span>سبب الحذف</span><Textarea value={reason} onChange={(event) => setReason(event.target.value)} placeholder="اكتب سبب الحذف لحفظه في سجل التدقيق" /></label><DialogFooter><Button variant="outline" onClick={onClose}>إلغاء</Button><Button variant="destructive" disabled={busy || reason.trim().length < 3} onClick={() => onDelete(reason.trim())}>حذف السجل</Button></DialogFooter></DialogContent></Dialog>; }
type Staff = { id: number; fullName: string; username: string; department?: string; salaryStatus?: string };
type Line = { id?: number; staff_id?: number; employeeId?: number; employeeName: string; department?: string; baseSalary: number; grossSalary: number; netSalary: number; totalDeductions?: number; advanceDeduction: number; attendanceDays: number; absenceDays: number; scheduledWorkingDays: number; overtimeHours: number; overtimeAmount: number; bonusAmount: number; penaltyAmount: number; absenceDeduction: number; totalAllowances?: number; attendanceAllowance?: number; transportationAllowance?: number; foodAllowance?: number; phoneAllowance?: number; housingAllowance?: number; otherFixedAllowances?: number; calculationDetails?: any; commissionAmount?: number; attendanceDeduction?: number; lateDeduction?: number; manualDeduction?: number; otherEarnings?: number; otherDeductions?: number; paymentMethod?: string; paymentDate?: string | null; lineNotes?: string | null; remainingSalary?: number };
type Run = { id: number; run_no: string; period: string; status: string; notes?: string; department?: string; totalGross: number; totalDeductions: number; totalNet: number; periodStartDate?: string; periodEndDate?: string; paymentDate?: string; attendanceWarning?: string | null; lines: Line[] };
type Dashboard = { employees: number; monthly_payroll: number; paid_salaries: number; pending_salaries: number; advances: number; bonuses: number; deductions: number; attendance: number; absence: number; late_employees: number; overtime: number; netSalary: number; departments: { department: string; employees: number; netSalary: number; lines: Line[] }[]; runs?: Run[] };
const money = new Intl.NumberFormat("ar-IQ", { style: "currency", currency: "IQD", maximumFractionDigits: 0 });
const printSalarySlipDetailed = printSalarySlip;
const date = () => new Date().toISOString().slice(0, 10); const period = () => date().slice(0, 7); const last = (p: string) => new Date(Date.UTC(Number(p.slice(0, 4)), Number(p.slice(5)), 0)).toISOString().slice(0, 10);

export default function HrPage() {
  const qc = useQueryClient(); const { toast } = useToast(); const [location, setLocation] = useLocation(); const [createOpen, setCreateOpen] = useState(false); const [previewOpen, setPreviewOpen] = useState(false); const [details, setDetails] = useState<Run | null>(null); const [departmentDetails, setDepartmentDetails] = useState<{ department: string; employees: number; netSalary: number; lines: Line[] } | null>(null); const [calculation, setCalculation] = useState<Line | null>(null); const [preview, setPreview] = useState<{ employees: Line[]; totals: { gross: number; deductions: number; net: number }; attendanceWarning?: string | null } | null>(null); const [conflict, setConflict] = useState<Run | null>(null); const [salaryIssues, setSalaryIssues] = useState<{ id: number; name: string; missing: string[] }[]>([]);
  const [form, setForm] = useState({ period: period(), department: "", employeeIds: [] as number[], periodStartDate: `${period()}-01`, periodEndDate: last(period()), paymentDate: last(period()), notes: "" });
  const [editTarget, setEditTarget] = useState<{ run: Run; line: Line } | null>(null); const [deleteTarget, setDeleteTarget] = useState<Run | null>(null); const [deleteLineTarget, setDeleteLineTarget] = useState<{ run: Run; line: Line } | null>(null); const [selected, setSelected] = useState<number[]>([]); const [focus, setFocus] = useState<string | null>(null); const [filters, setFilters] = useState({ month: period(), year: "", department: "", employee: "", status: "", paymentStatus: "", amountType: "", search: "" });
  useEffect(() => { setFocus(new URLSearchParams(window.location.search).get("focus")); }, []);
  const payrollParams = new URLSearchParams(Object.entries({ period: filters.month, year: filters.year, department: filters.department, employee: filters.employee, status: filters.status, paymentStatus: filters.paymentStatus, amountType: filters.amountType, search: filters.search }).filter(([, value]) => Boolean(value)) as [string, string][]).toString();
  const payroll = useQuery({ queryKey: ["hr", "payroll", payrollParams], queryFn: () => adminFetch<Run[]>(`/admin/hr/payroll${payrollParams ? `?${payrollParams}` : ""}`) });
  const dashboard = useQuery({ queryKey: ["hr", "payroll", "dashboard", filters.month], queryFn: () => adminFetch<Dashboard>(`/admin/hr/payroll/dashboard?period=${filters.month || form.period}`) });
  const routePayrollId = /^\/admin\/payroll\/(\d+)$/.exec(location)?.[1];
  const routeRun = useQuery({ queryKey: ["hr", "payroll", "detail", routePayrollId], queryFn: () => adminFetch<Run>(`/admin/hr/payroll/${routePayrollId}`), enabled: Boolean(routePayrollId) });
  useEffect(() => { if (routeRun.data) setDetails(routeRun.data); }, [routeRun.data]);
  const staff = useQuery({ queryKey: ["admin", "staff"], queryFn: () => adminFetch<Staff[]>("/admin/staff"), enabled: createOpen });
  const refresh = () => { qc.invalidateQueries({ queryKey: ["hr", "payroll"] }); qc.invalidateQueries({ queryKey: ["hr", "bonuses"] }); };
  const openRun = (run: Run) => { setDetails(run); setLocation(`/admin/payroll/${run.id}`); toast({ title: "تم فتح تفاصيل دورة الرواتب" }); };
  const employees = useMemo(() => (staff.data ?? []).filter((s) => s.salaryStatus !== "suspended" && (!form.department || s.department === form.department)), [staff.data, form.department]);
  const departments = useMemo(() => [...new Set((staff.data ?? []).map((s) => s.department || "general"))], [staff.data]);
  const previewMutation = useMutation({ mutationFn: () => adminFetch<any>("/admin/hr/payroll/preview", { method: "POST", body: JSON.stringify(form) }), onSuccess: (data) => { setPreview(data); setPreviewOpen(true); }, onError: (error: any) => handlePayrollError(error, setSalaryIssues, setConflict, payroll.data, form.period, toast) });
  const create = useMutation({ mutationFn: () => adminFetch<Run>("/admin/hr/payroll", { method: "POST", body: JSON.stringify(form) }), onSuccess: (run) => { refresh(); setCreateOpen(false); setPreviewOpen(false); setConflict(null); setSalaryIssues([]); toast({ title: "تم إنشاء الرواتب", description: `تم إنشاء ${run.lines.length} سجل رواتب بنجاح.` }); }, onError: (error: any) => handlePayrollError(error, setSalaryIssues, setConflict, payroll.data, form.period, toast) });
  const recalculate = useMutation({ mutationFn: (id: number) => adminFetch<Run>(`/admin/hr/payroll/${id}/recalculate`, { method: "POST" }), onSuccess: (run) => { refresh(); setDetails(run); setConflict(null); toast({ title: "تمت إعادة حساب الرواتب" }); }, onError: (e) => toast({ title: "تعذرت إعادة الحساب", description: apiErrorMessage(e), variant: "destructive" }) });
  const submit = useMutation({ mutationFn: (id: number) => adminFetch<Run>(`/admin/hr/payroll/${id}/submit`, { method: "POST" }), onSuccess: (run) => { refresh(); setDetails(run); toast({ title: "تم إرسال دورة الرواتب لاعتماد المدير" }); }, onError: (e) => toast({ title: "تعذر إرسال الدورة", description: apiErrorMessage(e), variant: "destructive" }) });
  const deleteDraft = useMutation({ mutationFn: (id: number) => adminFetch(`/admin/hr/payroll/${id}`, { method: "DELETE" }), onSuccess: () => { refresh(); setConflict(null); toast({ title: "تم حذف مسودة الرواتب" }); }, onError: (e) => toast({ title: "تعذر حذف المسودة", description: apiErrorMessage(e), variant: "destructive" }) });
  const approve = useMutation({ mutationFn: (id: number) => adminFetch<Run>(`/admin/hr/payroll/${id}/approve`, { method: "POST" }), onSuccess: (run) => { refresh(); setDetails(run); toast({ title: "تم اعتماد الرواتب" }); }, onError: (e) => toast({ title: "تعذر الاعتماد", description: apiErrorMessage(e), variant: "destructive" }) });
  const pay = useMutation({ mutationFn: (id: number) => adminFetch<Run>(`/admin/hr/payroll/${id}/pay`, { method: "POST" }), onSuccess: (run) => { refresh(); setDetails(run); toast({ title: "تم دفع الرواتب وتسجيل الحركة المالية" }); }, onError: (e) => toast({ title: "تعذر الدفع", description: apiErrorMessage(e), variant: "destructive" }) });
  const edit = useMutation({ mutationFn: ({ runId, lineId, values }: { runId: number; lineId: number; values: any }) => adminFetch<any>(`/admin/hr/payroll/${runId}/lines/${lineId}`, { method: "PATCH", body: JSON.stringify(values) }), onSuccess: (result) => { refresh(); setEditTarget(null); if (result?.run) setDetails(result.run); toast({ title: "تم تعديل الراتب بنجاح" }); }, onError: (e) => toast({ title: "تعذر تعديل الراتب", description: apiErrorMessage(e), variant: "destructive" }) });
  const deleteLine = useMutation({ mutationFn: ({ runId, lineId, reason }: { runId: number; lineId: number; reason: string }) => adminFetch<Run>(`/admin/hr/payroll/${runId}/lines/${lineId}`, { method: "DELETE", body: JSON.stringify({ reason }) }), onSuccess: (run) => { refresh(); setDeleteLineTarget(null); setDetails(run); toast({ title: "تم حذف سجل الموظف من المسودة" }); }, onError: (e) => toast({ title: "تعذر حذف سجل الموظف", description: apiErrorMessage(e), variant: "destructive" }) });
  const openCreate = () => { const p = period(); setForm({ period: p, department: "", employeeIds: [], periodStartDate: `${p}-01`, periodEndDate: last(p), paymentDate: last(p), notes: "" }); setPreview(null); setConflict(null); setSalaryIssues([]); setCreateOpen(true); };
  const setPayrollPeriod = (value: string) => setForm((f) => ({ ...f, period: value, periodStartDate: `${value}-01`, periodEndDate: last(value), paymentDate: last(value) }));
  const toggle = (id: number) => setForm((f) => ({ ...f, employeeIds: f.employeeIds.includes(id) ? f.employeeIds.filter((x) => x !== id) : [...f.employeeIds, id] }));
  const toggleSelected = (id: number) => setSelected((ids) => ids.includes(id) ? ids.filter((x) => x !== id) : [...ids, id]);
  const selectedRuns = (payroll.data ?? []).filter((run) => selected.includes(run.id));
  const bulk = async (action: "recalculate" | "submit" | "approve" | "delete" | "cancel" | "print") => {
    if (action === "print") { selectedRuns.forEach((run) => printSalarySlip(run)); return; }
    const eligible = selectedRuns.filter((run) => action === "delete" ? ["draft", "calculated", "cancelled"].includes(run.status) : action === "cancel" ? !["paid", "cancelled"].includes(run.status) : action === "recalculate" ? ["draft", "calculated", "under_review"].includes(run.status) : action === "submit" ? ["draft", "calculated", "under_review", "rejected"].includes(run.status) : run.status === "pending_manager_approval");
    const skipped = selectedRuns.length - eligible.length; let failed = 0;
    await Promise.all(eligible.map(async (run) => { try { if (action === "delete") await adminFetch(`/admin/hr/payroll/${run.id}`, { method: "DELETE" }); else if (action === "cancel") await adminFetch(`/admin/hr/payroll/${run.id}/cancel`, { method: "POST", body: JSON.stringify({ reason: "إلغاء جماعي" }) }); else await adminFetch(`/admin/hr/payroll/${run.id}/${action}`, { method: "POST" }); } catch { failed++; } }));
    refresh(); setSelected([]); toast({ title: "نتيجة الإجراء الجماعي", description: `تمت المعالجة: ${eligible.length - failed} · تم التخطي: ${skipped} · فشل: ${failed}` });
  };
  const stats = dashboard.data;
  const openFocus = (key: string) => { setFocus(key); window.history.pushState({}, "", `/admin/hr?tab=payroll&focus=${key}`); };
  const closeFocus = () => { setFocus(null); window.history.pushState({}, "", "/admin/hr?tab=payroll"); };
  const summaryCards: { key: string; label: string; value: number | undefined; currency?: boolean }[] = [
    { key: "employees", label: "الموظفون", value: stats?.employees },
    { key: "monthly", label: "رواتب الشهر", value: stats?.monthly_payroll, currency: true },
    { key: "bonuses", label: "المكافآت", value: stats?.bonuses, currency: true },
    { key: "deductions", label: "الاستقطاعات", value: stats?.deductions, currency: true },
    { key: "attendance", label: "الحضور", value: stats?.attendance },
    { key: "absence", label: "الغياب", value: stats?.absence },
    { key: "overtime", label: "الإضافي (ساعة)", value: stats?.overtime },
    { key: "late", label: "المتأخرون", value: stats?.late_employees },
    { key: "advances", label: "السلف", value: stats?.advances, currency: true },
    { key: "paid", label: "المدفوع", value: stats?.paid_salaries, currency: true },
    { key: "pending", label: "قيد الانتظار", value: stats?.pending_salaries, currency: true },
    { key: "net-salary", label: "صافي الرواتب", value: stats?.netSalary, currency: true },
  ];
  return <div className="space-y-5" dir="rtl"><div className="flex flex-wrap items-center justify-between gap-3"><div className="flex items-center gap-2"><span className="grid h-10 w-10 place-items-center rounded-xl bg-primary/15 text-primary"><Users /></span><div><h1 className="text-2xl font-bold">إدارة الرواتب</h1><p className="text-sm text-muted-foreground">الحضور، السلف، الحسابات، والدفع من الصندوق الرئيسي.</p></div></div><Button onClick={openCreate}><Plus className="ms-1 h-4 w-4" />إنشاء رواتب</Button></div>
    <section className="rounded-xl border border-border/50 bg-card p-3"><div className="mb-2 flex items-center gap-2 text-sm font-semibold"><Search className="h-4 w-4 text-primary" />بحث وتصفية الرواتب</div><div className="grid gap-2 sm:grid-cols-2 lg:grid-cols-4"><input type="month" value={filters.month} onChange={(event) => setFilters((current) => ({ ...current, month: event.target.value, year: "" }))} className="rounded-md border bg-background p-2 text-sm" aria-label="شهر الرواتب" /><input value={filters.department} onChange={(event) => setFilters((current) => ({ ...current, department: event.target.value }))} placeholder="القسم" className="rounded-md border bg-background p-2 text-sm" /><input value={filters.employee} onChange={(event) => setFilters((current) => ({ ...current, employee: event.target.value }))} placeholder="الموظف أو رمز الموظف" className="rounded-md border bg-background p-2 text-sm" /><select value={filters.status} onChange={(event) => setFilters((current) => ({ ...current, status: event.target.value }))} className="rounded-md border bg-background p-2 text-sm"><option value="">كل حالات الرواتب</option><option value="draft">مسودة</option><option value="calculated">محسوبة</option><option value="under_review">قيد المراجعة</option><option value="approved">معتمدة</option><option value="paid">مدفوعة</option><option value="cancelled">ملغاة</option></select><select value={filters.paymentStatus} onChange={(event) => setFilters((current) => ({ ...current, paymentStatus: event.target.value }))} className="rounded-md border bg-background p-2 text-sm"><option value="">كل حالات الدفع</option><option value="unpaid">غير مدفوع</option><option value="partially_paid">مدفوع جزئياً</option><option value="paid">مدفوع</option></select><select value={filters.amountType} onChange={(event) => setFilters((current) => ({ ...current, amountType: event.target.value }))} className="rounded-md border bg-background p-2 text-sm"><option value="">كل أنواع المبالغ</option><option value="salary">راتب أساسي</option><option value="bonus">مكافأة</option><option value="overtime">إضافي</option><option value="deduction">استقطاع</option><option value="advance">خصم سلفة</option></select><label className="relative"><Search className="pointer-events-none absolute end-3 top-3 h-4 w-4 text-muted-foreground" /><input value={filters.search} onChange={(event) => setFilters((current) => ({ ...current, search: event.target.value }))} placeholder="اسم، كود، رقم دورة، مرجع مكافأة…" className="w-full rounded-md border bg-background py-2 pe-9 ps-2 text-sm" /></label><Button variant="outline" onClick={() => setFilters({ month: period(), year: "", department: "", employee: "", status: "", paymentStatus: "", amountType: "", search: "" })}>مسح الفلاتر</Button></div></section>
    {dashboard.isLoading ? <div className="grid grid-cols-2 gap-3 lg:grid-cols-5">{Array.from({ length: 12 }).map((_, i) => <div key={i} className="h-20 animate-pulse rounded-xl bg-muted" />)}</div> : <><div className="grid grid-cols-2 gap-3 lg:grid-cols-5">{summaryCards.map((card) => <button type="button" key={card.key} onClick={() => openFocus(card.key)} aria-pressed={focus === card.key} className={`rounded-xl border border-border/50 bg-card p-3 text-right transition hover:border-primary/60 hover:bg-primary/5 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary ${focus === card.key ? "border-primary bg-primary/10" : ""}`}><p className="text-xs text-muted-foreground">{card.label}</p><p className="mt-1 text-lg font-bold">{card.currency ? money.format(card.value ?? 0) : Number(card.value ?? 0).toLocaleString("ar-IQ")}</p><span className="mt-1 block text-[11px] text-primary">عرض التفاصيل</span></button>)}</div>{focus && <PayrollFocusPanel focus={focus} stats={stats} runs={payroll.data ?? []} onClose={closeFocus} />}<section className="rounded-xl border border-border/50 bg-card p-4"><h2 className="mb-3 font-semibold">ملخص الأقسام</h2><div className="grid gap-2 sm:grid-cols-2 lg:grid-cols-4">{stats?.departments.map((item) => <div key={item.department} className="rounded-lg bg-muted/50 p-3 text-sm"><b>{item.department}</b><div className="mt-1 text-muted-foreground">{item.employees} موظف</div><button type="button" onClick={() => { setDepartmentDetails(item); toast({ title: "تم فتح تفاصيل المبلغ" }); }} className="mt-2 font-bold text-primary underline decoration-primary/40 underline-offset-4 hover:text-primary/80 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary">{money.format(item.netSalary)}</button></div>)}</div></section></>}
    <section className="rounded-xl border border-border/50 bg-card p-4"><div className="mb-3 flex items-center gap-2 font-semibold"><Wallet className="h-4 w-4 text-primary" />دورات الرواتب</div>{payroll.isLoading ? <div className="h-32 animate-pulse rounded-lg bg-muted" /> : <div className="overflow-x-auto"><table className="w-full min-w-[850px] text-sm"><thead className="text-muted-foreground"><tr><th className="p-2 text-right">الدورة</th><th className="text-right">الشهر</th><th className="text-right">الموظفون</th><th className="text-right">الإجمالي</th><th className="text-right">الاستقطاعات</th><th className="text-right">الصافي</th><th className="text-right">الحالة</th><th /></tr></thead><tbody>{payroll.data?.map((run) => <tr key={run.id} role="button" tabIndex={0} onClick={() => openRun(run)} onKeyDown={(event) => event.key === "Enter" && openRun(run)} className="cursor-pointer border-t transition-colors hover:bg-primary/[0.04] focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary"><td className="p-2 font-medium text-primary">{run.run_no}</td><td>{run.period}</td><td>{run.lines.length}</td><td>{money.format(run.totalGross)}</td><td>{money.format(run.totalDeductions)}</td><td className="font-semibold">{money.format(run.totalNet)}</td><td>{run.status}</td><td><Button size="sm" variant="outline" onClick={(event) => { event.stopPropagation(); openRun(run); }}><Eye className="ms-1 h-3.5 w-3.5" />التفاصيل</Button></td></tr>)}</tbody></table>{!payroll.data?.length && <p className="py-10 text-center text-sm text-muted-foreground">لا توجد دورات مطابقة للفلاتر. إذا كانت هناك إجماليات، غيّر الشهر أو امسح الفلاتر.</p>}</div>}</section>
    {selected.length > 0 && <div className="flex flex-wrap gap-2 rounded-lg border border-primary/20 bg-primary/5 p-2"><span className="self-center text-sm font-medium">الإجراءات الجماعية ({selected.length})</span><Button size="sm" variant="outline" onClick={() => bulk("recalculate")}><RefreshCw className="ms-1 h-3.5 w-3.5" />إعادة حساب المحدد</Button><Button size="sm" variant="outline" onClick={() => bulk("submit")}>إرسال لاعتماد المدير</Button><Button size="sm" variant="outline" onClick={() => bulk("approve")}><Check className="ms-1 h-3.5 w-3.5" />اعتماد وصرف المحدد</Button><Button size="sm" variant="outline" onClick={() => bulk("delete")}><Trash2 className="ms-1 h-3.5 w-3.5" />حذف المسودات</Button><Button size="sm" variant="outline" onClick={() => bulk("cancel")}>إلغاء المحدد</Button><Button size="sm" variant="outline" onClick={() => bulk("print")}><Printer className="ms-1 h-3.5 w-3.5" />طباعة المحدد</Button></div>}
    <PayrollBonuses active={focus === "bonuses"} />
    <PayrollActions runs={payroll.data ?? []} selected={selected} toggleSelected={toggleSelected} setSelected={setSelected} setDetails={setDetails} setEditTarget={setEditTarget} setDeleteTarget={setDeleteTarget} recalculate={recalculate} submit={submit} approve={approve} pay={pay} print={printSalarySlip} bulk={bulk} />
    <CreateDialog open={createOpen} setOpen={setCreateOpen} form={form} setForm={setForm} setPayrollPeriod={setPayrollPeriod} departments={departments} employees={employees} toggle={toggle} preview={previewMutation} create={create} issues={salaryIssues} />
    <Dialog open={previewOpen} onOpenChange={setPreviewOpen}><DialogContent className="max-w-5xl" dir="rtl"><DialogHeader><DialogTitle>معاينة حساب الرواتب</DialogTitle><DialogDescription>هذه المعاينة لم تنشئ أي سجلات مالية أو دفعات.</DialogDescription></DialogHeader>{preview?.attendanceWarning && <p className="rounded-md bg-amber-500/10 p-2 text-sm text-amber-700">{preview.attendanceWarning}</p>}<PreviewTable lines={preview?.employees ?? []} onCalculation={setCalculation} /><div className="grid grid-cols-3 gap-2 rounded-lg bg-muted p-3 text-sm"><Stat label="الإجمالي" value={money.format(preview?.totals.gross ?? 0)} /><Stat label="الاستقطاعات" value={money.format(preview?.totals.deductions ?? 0)} /><Stat label="الصافي" value={money.format(preview?.totals.net ?? 0)} /></div><DialogFooter><Button variant="outline" onClick={() => setPreviewOpen(false)}>رجوع</Button><Button onClick={() => create.mutate()} disabled={create.isPending}>{create.isPending && <Loader2 className="ms-1 h-4 w-4 animate-spin" />}تأكيد إنشاء الرواتب</Button></DialogFooter></DialogContent></Dialog>
    <ConflictDialog run={conflict} onOpen={(run: Run) => { setDetails(run); setCreateOpen(false); }} onRecalculate={recalculate.mutate} onDelete={deleteDraft.mutate} onCancel={() => setConflict(null)} />
    <DepartmentAmountDialog department={departmentDetails} onClose={() => setDepartmentDetails(null)} onOpenRun={(payrollId: number) => { const run = (dashboard.data?.runs ?? payroll.data ?? []).find((item: Run) => item.id === payrollId); if (run) openRun(run); else setLocation(`/admin/payroll/${payrollId}`); }} onOpenCalculation={setCalculation} />
    <DetailsDialog run={details} onClose={() => setDetails(null)} onCalculation={setCalculation} onSubmit={submit.mutate} onApprove={approve.mutate} onPay={pay.mutate} onEditLine={(run: Run, line: Line) => setEditTarget({ run, line })} onDeleteLine={(run: Run, line: Line) => setDeleteLineTarget({ run, line })} />
    <CalculationDialog line={calculation} onClose={() => setCalculation(null)} />
    <EditPayrollDialog target={editTarget} onClose={() => setEditTarget(null)} onSave={(values: any) => editTarget && edit.mutate({ runId: editTarget.run.id, lineId: Number(editTarget.line.id), values })} saving={edit.isPending} />
    <DeletePayrollDialog run={deleteTarget} onClose={() => setDeleteTarget(null)} onDelete={() => { if (deleteTarget) deleteDraft.mutate(deleteTarget.id); setDeleteTarget(null); }} />
    <DeletePayrollLineDialog target={deleteLineTarget} onClose={() => setDeleteLineTarget(null)} onDelete={(reason: string) => deleteLineTarget && deleteLine.mutate({ runId: deleteLineTarget.run.id, lineId: Number(deleteLineTarget.line.id), reason })} busy={deleteLine.isPending} />
  </div>;
}

/** Inline destination for each dashboard summary card. Keeping this in the payroll page
 * means deep links such as ?tab=payroll&focus=bonuses work without a full page reload. */
function PayrollFocusPanel({ focus, stats, runs, onClose }: { focus: string; stats?: Dashboard; runs: Run[]; onClose: () => void }) {
  const labels: Record<string, string> = {
    employees: "الموظفون", monthly: "رواتب الشهر", bonuses: "المكافآت", deductions: "الاستقطاعات",
    attendance: "الحضور", absence: "الغياب", overtime: "الإضافي", late: "المتأخرون", advances: "السلف", paid: "المدفوع",
    pending: "قيد الانتظار", "net-salary": "صافي الرواتب",
  };
  const filteredRuns = focus === "paid" ? runs.filter((run) => run.status === "paid") : focus === "pending" ? runs.filter((run) => !["paid", "cancelled"].includes(run.status)) : runs;
  const lines = filteredRuns.flatMap((run) => run.lines.map((line) => ({ ...line, period: run.period, runStatus: run.status }))).filter((line) => focus !== "late" || (line.lateDeduction ?? 0) > 0);
  const metric = (line: Line) => focus === "bonuses" ? line.bonusAmount ?? 0 : focus === "deductions" ? line.totalDeductions ?? 0 : focus === "advances" ? line.advanceDeduction ?? 0 : focus === "overtime" ? line.overtimeHours ?? 0 : focus === "attendance" ? line.attendanceDays ?? 0 : focus === "absence" ? line.absenceDays ?? 0 : focus === "late" ? line.lateDeduction ?? 0 : line.netSalary ?? 0;
  const currencyMetric = ["bonuses", "deductions", "advances", "monthly", "paid", "pending", "net-salary"].includes(focus);
  const value = focus === "employees" ? stats?.employees ?? lines.length : focus === "monthly" ? stats?.monthly_payroll ?? 0 : focus === "paid" ? stats?.paid_salaries ?? 0 : focus === "pending" ? stats?.pending_salaries ?? 0 : focus === "net-salary" ? stats?.netSalary ?? 0 : focus === "late" ? stats?.late_employees ?? 0 : stats?.[focus as keyof Dashboard] as number ?? 0;
  return <section className="rounded-xl border border-primary/30 bg-card p-4 shadow-sm" aria-live="polite"><div className="mb-3 flex items-center justify-between gap-2"><div><h2 className="font-semibold">{labels[focus] ?? "تفاصيل الرواتب"}</h2><p className="text-xs text-muted-foreground">تتحدث البيانات فور إعادة احتساب أي راتب.</p></div><Button size="sm" variant="ghost" onClick={onClose}>إغلاق</Button></div><div className="mb-4 rounded-lg bg-primary/5 p-3"><span className="text-xs text-muted-foreground">الإجمالي</span><p className="text-xl font-bold">{currencyMetric ? money.format(value) : Number(value).toLocaleString("ar-IQ")}</p></div>{focus === "monthly" || focus === "paid" || focus === "pending" || focus === "net-salary" || focus === "employees" ? <div className="overflow-x-auto"><table className="w-full min-w-[640px] text-sm"><thead className="text-muted-foreground"><tr><th className="p-2 text-right">الموظف</th><th className="text-right">الفترة</th><th className="text-right">الحالة</th><th className="text-right">الصافي</th></tr></thead><tbody>{lines.slice(0, 100).map((line) => <tr key={`${line.period}-${line.id ?? line.employeeId}`} className="border-t"><td className="p-2">{line.employeeName}</td><td>{line.period}</td><td>{line.runStatus}</td><td className="font-semibold">{money.format(line.netSalary ?? 0)}</td></tr>)}</tbody></table>{!lines.length && <p className="py-6 text-center text-sm text-muted-foreground">لا توجد سجلات لهذه البطاقة.</p>}</div> : <div className="overflow-x-auto"><table className="w-full min-w-[640px] text-sm"><thead className="text-muted-foreground"><tr><th className="p-2 text-right">الموظف</th><th className="text-right">الفترة</th><th className="text-right">القيمة</th><th className="text-right">الحالة</th></tr></thead><tbody>{lines.slice(0, 100).map((line) => <tr key={`${line.period}-${line.id ?? line.employeeId}`} className="border-t"><td className="p-2">{line.employeeName}</td><td>{line.period}</td><td className="font-semibold">{currencyMetric ? money.format(metric(line)) : Number(metric(line)).toLocaleString("ar-IQ")}</td><td>{line.runStatus}</td></tr>)}</tbody></table>{!lines.length && <p className="py-6 text-center text-sm text-muted-foreground">لا توجد سجلات لهذه البطاقة.</p>}</div>}</section>;
}

function CreateDialog({ open, setOpen, form, setForm, setPayrollPeriod, departments, employees, toggle, preview, create, issues }: any) { return <Dialog open={open} onOpenChange={setOpen}><DialogContent className="max-w-3xl" dir="rtl"><DialogHeader><DialogTitle>إنشاء دورة رواتب</DialogTitle><DialogDescription>اختر جميع الموظفين، قسماً، أو موظفين محددين.</DialogDescription></DialogHeader><div className="grid gap-3 sm:grid-cols-3"><Field label="شهر الرواتب"><input type="month" value={form.period} onChange={(e) => setPayrollPeriod(e.target.value)} /></Field><Field label="القسم"><select value={form.department} onChange={(e) => setForm((f: any) => ({ ...f, department: e.target.value, employeeIds: [] }))}><option value="">كل الأقسام</option>{departments.map((d: string) => <option key={d}>{d}</option>)}</select></Field><Field label="الموظفون"><span className="text-sm text-muted-foreground">{form.employeeIds.length ? `${form.employeeIds.length} محدد` : "جميع الموظفين النشطين"}</span></Field><Field label="بداية الفترة"><input type="date" value={form.periodStartDate} onChange={(e) => setForm((f: any) => ({ ...f, periodStartDate: e.target.value }))} /></Field><Field label="نهاية الفترة"><input type="date" value={form.periodEndDate} onChange={(e) => setForm((f: any) => ({ ...f, periodEndDate: e.target.value }))} /></Field><Field label="تاريخ الدفع"><input type="date" value={form.paymentDate} onChange={(e) => setForm((f: any) => ({ ...f, paymentDate: e.target.value }))} /></Field></div><div className="rounded-lg border p-3"><div className="mb-2 flex justify-between text-sm font-medium"><span>اختيار الموظفين</span><label className="flex items-center gap-2"><Checkbox checked={employees.length > 0 && form.employeeIds.length === employees.length} onCheckedChange={(checked) => setForm((f: any) => ({ ...f, employeeIds: checked ? employees.map((s: Staff) => s.id) : [] }))} />الجميع</label></div><div className="grid max-h-32 gap-2 overflow-y-auto sm:grid-cols-2">{employees.map((s: Staff) => <label key={s.id} className="flex items-center gap-2 text-sm"><Checkbox checked={form.employeeIds.includes(s.id)} onCheckedChange={() => toggle(s.id)} />{s.fullName || s.username}<span className="text-xs text-muted-foreground">({s.department})</span></label>)}</div></div><Field label="ملاحظات"><Textarea value={form.notes} onChange={(e) => setForm((f: any) => ({ ...f, notes: e.target.value }))} /></Field>{issues.length > 0 && <div className="rounded-lg border border-destructive/40 bg-destructive/5 p-3 text-sm"><b>إعدادات الراتب غير مكتملة:</b>{issues.map((item: any) => <div key={item.id} className="mt-2 flex items-center justify-between"><span>{item.name}: {item.missing.join("، ")}</span><a href="/admin/staff" className="inline-flex items-center gap-1 text-primary underline"><Settings2 className="h-3.5 w-3.5" />فتح إعدادات الراتب</a></div>)}</div>}<DialogFooter><Button variant="outline" onClick={() => setOpen(false)}>إلغاء</Button><Button variant="outline" onClick={() => preview.mutate()} disabled={preview.isPending}>{preview.isPending && <Loader2 className="ms-1 h-4 w-4 animate-spin" />}معاينة الحساب</Button><Button onClick={() => create.mutate()} disabled={create.isPending}>{create.isPending && <Loader2 className="ms-1 h-4 w-4 animate-spin" />}إنشاء الرواتب</Button></DialogFooter></DialogContent></Dialog>; }
function PreviewTable({ lines, onCalculation, run, onEdit, onDelete }: { lines: Line[]; onCalculation: (line: Line) => void; run?: Run; onEdit?: (line: Line) => void; onDelete?: (line: Line) => void }) { const editable = ["draft", "calculated", "under_review"].includes(run?.status ?? ""); const deletable = run?.status === "draft"; return <div className="max-h-[45vh] overflow-auto"><table className="w-full min-w-[980px] text-sm"><thead className="sticky top-0 bg-background text-muted-foreground"><tr><th className="p-2 text-right">الموظف</th><th>الأساسي</th><th>الحضور/الغياب</th><th>البدلات</th><th>الإضافي</th><th>السلفة</th><th>الاستقطاعات</th><th>الصافي</th><th>الإجراءات</th></tr></thead><tbody>{lines.map((line) => <tr key={line.employeeId ?? line.id} className="border-t"><td className="p-2">{line.employeeName}<div className="text-xs text-muted-foreground">{line.department}</div></td><td>{money.format(line.baseSalary)}</td><td>{line.attendanceDays}/{line.absenceDays}</td><td>{money.format(line.totalAllowances ?? 0)}</td><td>{money.format(line.overtimeAmount)}</td><td>{money.format(line.advanceDeduction)}</td><td>{money.format(line.totalDeductions ?? 0)}</td><td className="font-semibold text-emerald-600">{money.format(line.netSalary)}</td><td><div className="flex justify-center gap-1"><Button size="sm" variant="ghost" title="تفاصيل الحساب" onClick={() => onCalculation(line)}><Calculator className="h-4 w-4" /></Button>{onEdit && <Button size="sm" variant="ghost" title={editable ? "تعديل راتب الموظف" : "لا يمكن تعديل راتب في دورة ملغاة أو معتمدة أو مدفوعة"} disabled={!editable} onClick={() => onEdit(line)}><Pencil className="h-4 w-4" /></Button>}{onDelete && <Button size="sm" variant="ghost" className="text-destructive hover:text-destructive" title={deletable ? "حذف سجل الموظف من المسودة" : "لا يمكن حذف السجل إلا من دورة مسودة"} disabled={!deletable} onClick={() => onDelete(line)}><Trash2 className="h-4 w-4" /></Button>}</div></td></tr>)}</tbody></table></div>; }
function ConflictDialog({ run, onOpen, onRecalculate, onDelete, onCancel }: any) { return <Dialog open={!!run} onOpenChange={(open) => !open && onCancel()}><DialogContent dir="rtl"><DialogHeader><DialogTitle>الرواتب موجودة لهذه الفترة</DialogTitle><DialogDescription>لا يمكن إنشاء دورة مكررة لنفس الشهر.</DialogDescription></DialogHeader><DialogFooter><Button variant="outline" onClick={onCancel}>إلغاء</Button>{run?.status === "draft" && <Button variant="destructive" onClick={() => onDelete(run.id)}>حذف مسودة الرواتب</Button>}{["draft", "calculated"].includes(run?.status) && <Button variant="outline" onClick={() => onRecalculate(run.id)}>إعادة حساب الرواتب</Button>}<Button onClick={() => onOpen(run)}>فتح الرواتب الموجودة</Button></DialogFooter></DialogContent></Dialog>; }
function DepartmentAmountDialog({ department, onClose, onOpenRun, onOpenCalculation }: { department: { department: string; employees: number; netSalary: number; lines: Line[] } | null; onClose: () => void; onOpenRun: (id: number) => void; onOpenCalculation: (line: Line) => void }) { return <Dialog open={!!department} onOpenChange={(open) => !open && onClose()}><DialogContent className="max-w-6xl" dir="rtl"><DialogHeader><DialogTitle>تفاصيل مبلغ الرواتب — {department?.department}</DialogTitle><DialogDescription>{department?.employees ?? 0} موظف · {money.format(department?.netSalary ?? 0)}. كل صف يوضح مصدر المبلغ وتركيبه.</DialogDescription></DialogHeader><div className="max-h-[60vh] overflow-auto"><table className="w-full min-w-[1050px] text-sm"><thead className="sticky top-0 bg-background text-muted-foreground"><tr><th className="p-2 text-right">الموظف / الكود</th><th>الدورة</th><th>الأساسي</th><th>البدلات</th><th>المكافآت</th><th>الإضافي</th><th>الاستقطاعات</th><th>خصم السلفة</th><th>الصافي</th><th>المصدر والروابط</th><th /></tr></thead><tbody>{department?.lines.map((line: any) => <tr key={`${line.payrollId}-${line.id}`} className="border-t"><td className="p-2"><b>{line.employeeName}</b><div className="text-xs text-muted-foreground">{line.employeeCode || `EMP-${line.employeeId}`}</div></td><td><button className="text-primary underline" onClick={() => onOpenRun(line.payrollId)}>{line.payrollNumber || line.payrollPeriod}</button></td><td>{money.format(line.baseSalary)}</td><td>{money.format((line.attendanceAllowance || 0) + (line.transportationAllowance || 0) + (line.foodAllowance || 0) + (line.phoneAllowance || 0) + (line.housingAllowance || 0) + (line.otherFixedAllowances || 0))}</td><td>{money.format((line.bonusAmount || 0) + (line.commissionAmount || 0) + (line.otherEarnings || 0))}</td><td>{money.format(line.overtimeAmount || 0)}</td><td>{money.format(line.totalDeductions || 0)}</td><td>{money.format(line.advanceDeduction || 0)}</td><td className="font-semibold">{money.format(line.netSalary)}</td><td className="min-w-48 p-2 text-xs"><div className="mb-1">{line.sourceRecords?.bonuses?.length ? `مكافأة #${line.sourceRecords.bonuses[0].id}` : line.sourceRecords?.advances?.length ? `سلفة #${line.sourceRecords.advances[0].advance_id}` : "سجل الراتب"}</div><div className="flex flex-wrap gap-1"><a className="rounded bg-muted px-1.5 py-1 text-primary hover:bg-muted/70" href={`/admin/staff?employee=${line.employeeId}`}>فتح الموظف</a><button className="rounded bg-muted px-1.5 py-1 text-primary hover:bg-muted/70" onClick={() => onOpenRun(line.payrollId)}>فتح الدورة</button>{line.sourceRecords?.bonuses?.[0] && <a className="rounded bg-muted px-1.5 py-1 text-primary hover:bg-muted/70" href={`/admin/hr?tab=payroll&focus=bonuses&bonus=${line.sourceRecords.bonuses[0].id}`}>فتح المكافأة</a>}{line.sourceRecords?.advances?.[0] && <a className="rounded bg-muted px-1.5 py-1 text-primary hover:bg-muted/70" href={`/admin/employee-advances?advance=${line.sourceRecords.advances[0].advance_id}`}>فتح السلفة</a>}{line.sourceRecords?.accounting && <a className="rounded bg-muted px-1.5 py-1 text-primary hover:bg-muted/70" href={`/admin/accounting?transaction=${line.sourceRecords.accounting.id}`}>فتح القيد</a>}{line.sourceRecords?.cashboxTransactionId && <a className="rounded bg-muted px-1.5 py-1 text-primary hover:bg-muted/70" href={`/admin/master-cash?transaction=${line.sourceRecords.cashboxTransactionId}`}>حركة الصندوق</a>}</div></td><td><Button size="sm" variant="ghost" title="تفاصيل التركيب" onClick={() => onOpenCalculation(line)}><Eye className="h-4 w-4" /></Button></td></tr>)}</tbody></table></div></DialogContent></Dialog>; }
function DetailsDialog({ run, onClose, onCalculation, onSubmit, onApprove, onPay, onEditLine, onDeleteLine }: any) { const [tab, setTab] = useState("employees"); const tabs = [["employees", "الموظفون"], ["bonuses", "المكافآت"], ["deductions", "الاستقطاعات"], ["attendance", "الحضور"], ["overtime", "الإضافي"], ["advances", "السلف"], ["payments", "الدفعات"], ["accounting", "المحاسبة"], ["audit", "سجل التدقيق"], ["timeline", "الخط الزمني"]] as const; const lines = run?.lines ?? []; const tabLines = tab === "bonuses" ? lines.filter((line: Line) => line.bonusAmount > 0) : tab === "deductions" ? lines.filter((line: Line) => (line.totalDeductions ?? 0) > 0) : tab === "overtime" ? lines.filter((line: Line) => line.overtimeAmount > 0) : tab === "advances" ? lines.filter((line: Line) => line.advanceDeduction > 0) : lines; const history = tab === "audit" ? run?.auditLog ?? [] : run?.timeline ?? []; return <Dialog open={!!run} onOpenChange={(open) => !open && onClose()}><DialogContent className="max-w-6xl" dir="rtl"><DialogHeader><DialogTitle>تفاصيل دورة الرواتب — {run?.run_no}</DialogTitle><DialogDescription>الشهر: {run?.period} · الفترة: {run?.periodStartDate} إلى {run?.periodEndDate} · الدفع: {run?.paymentDate || "غير محدد"} · الحالة: {run?.status}</DialogDescription></DialogHeader>{run?.attendanceWarning && <p className="rounded-md bg-amber-500/10 p-2 text-sm text-amber-700">{run.attendanceWarning}</p>}<div className="grid grid-cols-2 gap-2 text-sm sm:grid-cols-4"><Stat label="الموظفون" value={String(lines.length)} /><Stat label="الإجمالي" value={money.format(run?.totalGross ?? 0)} /><Stat label="الاستقطاعات" value={money.format(run?.totalDeductions ?? 0)} /><Stat label="الصافي" value={money.format(run?.totalNet ?? 0)} /></div><div className="flex flex-wrap gap-2">{["draft", "calculated", "under_review", "rejected"].includes(run?.status) && <Button size="sm" onClick={() => onSubmit(run.id)}>إرسال لاعتماد المدير</Button>}{run?.status === "pending_manager_approval" && <Button size="sm" onClick={() => onApprove(run.id)}>اعتماد وصرف</Button>}{run?.status === "approved" && <Button size="sm" onClick={() => onPay(run.id)}>دفع من الصندوق الرئيسي</Button>}</div><div className="flex gap-1 overflow-x-auto border-b pb-2">{tabs.map(([value, label]) => <button key={value} onClick={() => setTab(value)} className={`shrink-0 rounded-md px-3 py-1.5 text-sm ${tab === value ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground hover:bg-muted/70"}`}>{label}</button>)}</div>{["audit", "timeline"].includes(tab) ? <div className="space-y-2 rounded-lg bg-muted/50 p-3 text-sm">{history.length ? history.map((item: any) => <div key={item.id} className="flex items-start justify-between gap-3 border-b border-border/40 pb-2 last:border-0"><div><b>{item.title || item.action}</b><p className="text-xs text-muted-foreground">{item.body || item.user_name || item.actor_name || "النظام"}</p></div><time className="shrink-0 text-xs text-muted-foreground">{new Date(item.created_at).toLocaleString("ar-IQ")}</time></div>) : <p className="text-muted-foreground">لا توجد أحداث مسجلة لهذه الدورة بعد.</p>}</div> : tab === "accounting" ? <div className="rounded-lg bg-muted/50 p-4 text-sm">{lines.some((line: any) => line.sourceRecords?.accounting || line.financial_transaction_id) ? "توجد قيود أو حركات مرتبطة. افتح مصدر الصف للوصول إلى القيد أو حركة الصندوق." : "لا توجد قيود محاسبية منشورة لهذه الدورة."}</div> : <PreviewTable lines={tabLines} onCalculation={onCalculation} run={run} onEdit={(line) => onEditLine?.(run, line)} onDelete={(line) => onDeleteLine?.(run, line)} />}</DialogContent></Dialog>; }
function CalculationDialog({ line, onClose }: { line: Line | null; onClose: () => void }) { const details = line?.calculationDetails ?? {}; return <Dialog open={!!line} onOpenChange={(open) => !open && onClose()}><DialogContent dir="rtl"><DialogHeader><DialogTitle>تفاصيل حساب الراتب — {line?.employeeName}</DialogTitle><DialogDescription>الصيغ والسجلات المصدر المستخدمة في الحساب.</DialogDescription></DialogHeader><div className="space-y-3 text-sm"><div className="grid grid-cols-2 gap-2"><Stat label="الراتب الأساسي" value={money.format(line?.baseSalary ?? 0)} /><Stat label="الصافي" value={money.format(line?.netSalary ?? 0)} /><Stat label="خصم الغياب" value={money.format(line?.absenceDeduction ?? 0)} /><Stat label="خصم السلفة" value={money.format(line?.advanceDeduction ?? 0)} /></div><section className="rounded-lg border p-3"><b>الصيغ</b>{Object.entries(details.formulas ?? {}).map(([key, value]) => <p key={key} className="mt-2 text-muted-foreground">{key}: {String(value)}</p>)}</section><section className="rounded-lg border p-3"><b>سجلات المصدر</b><pre className="mt-2 max-h-40 overflow-auto whitespace-pre-wrap text-xs text-muted-foreground">{JSON.stringify(details.sources ?? {}, null, 2)}</pre></section></div><DialogFooter><Button onClick={onClose}>إغلاق</Button></DialogFooter></DialogContent></Dialog>; }
function Field({ label, children }: { label: string; children: React.ReactNode }) { return <label className="grid gap-1 text-sm"><span className="text-muted-foreground">{label}</span><div className="[&>input]:w-full [&>input]:rounded-md [&>input]:border [&>input]:bg-background [&>input]:p-2 [&>select]:w-full [&>select]:rounded-md [&>select]:border [&>select]:bg-background [&>select]:p-2">{children}</div></label>; } function Stat({ label, value }: { label: string; value: string }) { return <div className="rounded-md bg-muted/60 p-2"><p className="text-xs text-muted-foreground">{label}</p><p className="font-semibold">{value}</p></div>; }
function handlePayrollError(error: any, setIssues: any, setConflict: any, runs: Run[] | undefined, payrollPeriod: string, toast: any) { if (apiErrorStatus(error) === 422) setIssues(error.data?.employees ?? []); if (apiErrorStatus(error) === 409) setConflict(error.data?.existing ?? runs?.find((run) => run.period === payrollPeriod) ?? null); toast({ title: "تعذر إكمال عملية الرواتب", description: apiErrorMessage(error), variant: "destructive" }); }
